const message = $json.message ?? {};
const from = message.from ?? {};
const chat = message.chat ?? {};
const text = typeof message.text === 'string' ? message.text.trim() : '';
const normalized = text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

function hasAny(values) {
  return values.some((value) => normalized.includes(value));
}

const positiveFeedback = new Set(['sim', 'ajudou', 'ok', 'boa', 'positivo']);
const negativeFeedback = new Set(['nao', 'nao ajudou', 'ruim', 'negativo']);

let intent = 'fallback';
let riskLevel = 'normal';
let isFeedback = false;
let feedbackValue = null;
let requiresLlm = Boolean(text);
let fixedReply = null;
let fallbackReason = null;

if (!text) {
  intent = 'non_text';
  requiresLlm = false;
  fallbackReason = 'non_text_message';
  fixedReply = 'Por enquanto eu so consigo responder mensagens de texto. Me diga sua duvida ou o treino que voce quer ajustar.';
} else if (normalized === '/start' || hasAny(['oi', 'ola', 'comecar', 'inicio'])) {
  intent = 'onboarding';
  requiresLlm = false;
  fallbackReason = 'rule_based_onboarding';
  fixedReply = 'Oi. Eu sou o Gym Buddy. Posso ajudar com duvidas rapidas de treino, descanso, falha, substituicoes e ideias gerais de treino curto. Me diga o que voce precisa agora.';
} else if (positiveFeedback.has(normalized)) {
  intent = 'feedback';
  isFeedback = true;
  feedbackValue = 'positive';
  requiresLlm = false;
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Valeu pelo feedback. Vou manter respostas curtas e praticas por aqui.';
} else if (negativeFeedback.has(normalized)) {
  intent = 'feedback';
  isFeedback = true;
  feedbackValue = 'negative';
  requiresLlm = false;
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Obrigado pelo feedback. Me diga em uma frase o que faltou ou o que voce queria ajustar.';
} else if (hasAny(['dor', 'doendo', 'machuquei', 'lesao', 'fisgada', 'formigamento', 'ombro', 'joelho', 'lombar', 'peito', 'tontura'])) {
  intent = 'discomfort';
  riskLevel = hasAny(['forte', 'aguda', 'fisgada', 'formigamento', 'peito', 'tontura', 'piorando']) ? 'stop' : 'caution';
  requiresLlm = false;
  fallbackReason = 'rule_based_safety';
  fixedReply = riskLevel === 'stop'
    ? 'Para agora e evite repetir o movimento que causou isso. Nao consigo diagnosticar pelo chat. Se a dor foi forte, aguda, esta piorando, teve formigamento, tontura ou dor no peito, procure avaliacao profissional ou atendimento urgente.'
    : 'Se apareceu dor ou desconforto, reduza ou pare o movimento por enquanto. Nao treine atravessando dor. Se persistir ou piorar, procure avaliacao profissional. Posso sugerir uma alternativa geral mais conservadora se voce me disser o exercicio.';
} else if (hasAny(['quantos kg', 'quanto peso', 'carga exata', 'qual carga', 'kg eu coloco'])) {
  intent = 'exact_load';
  requiresLlm = false;
  fallbackReason = 'rule_based_exact_load';
  fixedReply = 'Nao vou indicar kg exato sem avaliar tecnica e contexto. Use uma carga que voce controle bem e termine a serie com cerca de 1 a 3 repeticoes em reserva. Se a tecnica quebrar, reduza.';
} else if (hasAny(['lembra', 'ontem', 'treino anterior', 'ultima vez', 'semana passada'])) {
  intent = 'memory_request';
  requiresLlm = false;
  fallbackReason = 'rule_based_no_memory';
  fixedReply = 'Neste MVP eu nao lembro sessoes anteriores. Me reenvie o treino ou diga o objetivo de hoje que eu te ajudo a partir da mensagem atual.';
} else if (hasAny(['personalizado', 'personalizada', 'pra mim', 'para mim'])) {
  intent = 'personalized_workout_request';
  requiresLlm = false;
  fallbackReason = 'rule_based_personalization_boundary';
  fixedReply = 'Posso ajudar com uma estrutura geral, mas nao vou fingir personalizacao profunda sem avaliacao. Para ajustar melhor, me diga so 2 coisas: objetivo principal e equipamentos disponiveis.';
} else if (hasAny(['treino rapido', 'treino de 30', '30 min', '30 minutos', 'meia hora'])) {
  intent = 'short_workout';
  requiresLlm = false;
  fallbackReason = 'rule_based_short_workout';
  fixedReply = 'Ideia geral de treino de 30 min:\n\n1. Aquecimento: 5 min leve.\n2. Agachamento ou leg press: 3x8-12.\n3. Supino ou flexao: 3x8-12.\n4. Remada: 3x8-12.\n5. Levantamento terra romeno ou mesa flexora: 2x10-12.\n6. Prancha: 2x30-45s.\n\nDescanse 60-90s. Use carga controlavel e pare se sentir dor fora do normal. Isso ajudou?';
} else if (hasAny(['descanso', 'descansar', 'intervalo'])) {
  intent = 'rest_question';
  requiresLlm = false;
  fallbackReason = 'rule_based_rest';
  fixedReply = 'Como regra geral: 1-2 min funciona bem para exercicios leves ou isoladores; 2-3 min costuma ajudar em exercicios pesados como agachamento, supino e remada. Se a tecnica cair muito, descanse mais.';
} else if (hasAny(['falha', 'ate a falha', 'rir', 'repeticoes em reserva'])) {
  intent = 'failure_question';
  requiresLlm = false;
  fallbackReason = 'rule_based_failure';
  fixedReply = 'Nao precisa ir ate a falha em toda serie. Uma boa referencia e terminar muitas series com 1 a 3 repeticoes em reserva. Falha pode ser util em alguns momentos, mas aumenta fadiga e risco de perder tecnica.';
} else if (hasAny(['trocar', 'substituir', 'substituicao', 'no lugar de', 'alternativa'])) {
  intent = 'substitution';
  requiresLlm = false;
  fallbackReason = 'rule_based_substitution';
  fixedReply = 'Pode fazer sentido trocar, mas exercicios parecidos nao sao identicos. Se for por equipamento ou preferencia, me diga o exercicio atual e a opcao que voce tem. Se for por dor, pare o movimento e trate como sinal de cautela.';
}

const systemPrompt = `Voce e o Gym Buddy, um assistente pratico de apoio a treino para conversas pelo Telegram.

Seu objetivo neste MVP e ajudar o usuario com orientacoes gerais, curtas e seguras sobre treino, sem fingir personalizacao profunda e sem lembrar sessoes anteriores.

Escopo permitido:
- abrir uma sessao e explicar rapidamente como pode ajudar;
- responder duvidas avulsas sobre treino;
- sugerir substituicao simples de exercicio quando o motivo for equipamento, preferencia ou conforto geral;
- montar uma ideia geral de treino curto quando o usuario pedir algo simples;
- explicar conceitos de treino em linguagem simples;
- redirecionar casos de dor, lesao ou risco para uma conduta segura;
- receber feedback simples sobre a resposta.

Escopo proibido:
- nao diagnosticar lesoes, doencas ou causas de dor;
- nao propor tratamento de lesao;
- nao propor reabilitacao;
- nao fazer prescricao individual como se conhecesse historico, avaliacao fisica ou restricoes do usuario;
- nao indicar carga absoluta em kg;
- nao prometer resultado;
- nao fingir personalizacao profunda;
- nao lembrar, citar ou depender de sessoes anteriores;
- nao dizer que consultou base de conhecimento, arquivos, Google Drive, embeddings, RAG ou memoria externa;
- nao interpretar imagem, video ou exame.

Regras de seguranca:
Se o usuario mencionar dor forte, dor aguda, dor que piora, formigamento, perda de forca, tontura, falta de ar incomum, dor no peito, queda, trauma, lesao recente ou qualquer sinal de risco: nao trate como duvida normal de treino; recomende parar o exercicio ou evitar o movimento que provoca o sintoma; diga que nao consegue diagnosticar; oriente procurar avaliacao de profissional qualificado, e atendimento urgente se houver sinal grave; ofereca apenas alternativas gerais e conservadoras se fizer sentido.

Personalizacao:
Este MVP nao tem memoria longitudinal. Nao diga que lembra treino, objetivo, historico, lesao ou preferencia do usuario. Quando faltar contexto, responda de forma geral ou faca no maximo 2 perguntas curtas. Deixe claro quando a resposta e uma orientacao geral.

Cargas e intensidade:
Nao indique carga absoluta em kg. Se o usuario pedir carga exata, explique que isso depende de tecnica, experiencia, fadiga e seguranca. Sugira uma referencia subjetiva, como usar uma carga que permita boa tecnica e termine a serie com cerca de 1 a 3 repeticoes em reserva, quando apropriado.

Treino curto:
Quando o usuario pedir treino curto e nao houver sinais de risco, voce pode sugerir um treino geral com aquecimento breve, 4 a 6 exercicios, series/repeticoes ou tempo, descanso aproximado e observacao de tecnica e seguranca. Nao apresente como plano individual definitivo.

Substituicao de exercicio:
Quando o usuario pedir troca de exercicio, diga se a troca e plausivel em termos gerais, mencione que exercicios parecidos nao sao identicos, pergunte o motivo da troca quando isso for importante e aplique as regras de seguranca se o motivo for dor ou lesao.

Estilo:
Responda em pt-BR, de forma curta, direta e util para Telegram. Use frases simples e listas curtas quando ajudarem. Evite aulas longas, jargoes sem explicacao, excesso de disclaimers, respostas em JSON e inventar dados sobre o usuario.

Feedback simples:
Quando fizer sentido, termine com uma pergunta curta de feedback, por exemplo: Isso ajudou? Responda com "sim", "nao" ou diga o que quer ajustar.`;

const userPrompt = `Canal: Telegram\nuser_id: ${from.id ?? ''}\nchat_id: ${chat.id ?? ''}\nusername: ${from.username ?? ''}\nIntent detectada: ${intent}\nRisco: ${riskLevel}\nMensagem atual do usuario:\n${text}`;

return [
  {
    json: {
      channel: 'telegram',
      user_id: from.id ?? null,
      chat_id: chat.id ?? null,
      username: from.username ?? null,
      first_name: from.first_name ?? null,
      message_id: message.message_id ?? null,
      message_text: text,
      message_type: text ? 'text' : 'non_text',
      received_at: message.date ? new Date(message.date * 1000).toISOString() : new Date().toISOString(),
      intent,
      risk_level: riskLevel,
      is_feedback: isFeedback,
      feedback_value: feedbackValue,
      requires_llm: requiresLlm,
      fixed_reply: fixedReply,
      fallback_reason: fallbackReason,
      system_prompt: systemPrompt,
      user_prompt: userPrompt
    }
  }
];

const source = $('Extract Telegram Fields').first().json;
const errorMessage = $json.error?.message ?? $json.message ?? $json.description ?? null;
const errorCode = $json.error?.code ?? $json.httpCode ?? $json.statusCode ?? null;
const hasLlmError = Boolean($json.error || errorMessage?.toLowerCase?.().includes('quota') || errorCode);
const candidate = $json.text ?? $json.message?.content ?? $json.data?.[0]?.message?.content ?? $json.data?.[0]?.text ?? $json.choices?.[0]?.message?.content ?? '';
const modelReply = String(candidate || '').trim();
const replyText = hasLlmError
  ? 'Estou com instabilidade para gerar a resposta agora. Sua mensagem chegou, mas o motor de IA nao conseguiu responder neste momento. Tente novamente em alguns minutos.'
  : (modelReply || 'Nao consegui gerar uma resposta agora. Tente reformular a mensagem em texto.');

return [
  {
    json: {
      ...source,
      reply_text: replyText,
      handled_at: new Date().toISOString(),
      llm_status: hasLlmError ? 'error' : 'success',
      llm_error_code: errorCode,
      llm_error_message: errorMessage
    }
  }
];

return [
  {
    json: {
      ...$json,
      reply_text: $json.fixed_reply,
      handled_at: new Date().toISOString()
    }
  }
];
